begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('2f780832-1d12-5f00-b403-4679b2a0f7cb', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-06', '16:30:00', null, '通常 / ジャンプゲーム（ジャンプの仕方を整理）', 'まず完成形を遊んでもらい、カードを示しました。自分なりにプログラムを進めたかったほうです。最初に障害物のプログラムを作りました。プログラムの実行順序に対する意識が薄く、「最初の位置に戻る」という考え方に苦戦していました。座標については今日はかなりしつこくやりました。 ジャンプの考え方はおおよそ理解できている様子でした。「～回繰り返す」のブロックにあまり慣れきれないようでした。ぶつかるとプログラムを止めるところまで進めました。 来週以降は自分の作成しているオリジナル作品に取り組みたいようです。すでにある程度作ってありますが、ごちゃごちゃしてしまっているので整理する必要があるようです。', 'オリジナル作品の見直しから入る予定です。', 'タイピング: 集中して取り組めていました。
盛り上がり: スプライトの色を変えてかわいくアレンジしていました！'),
  ('e9b6d5ff-1a26-5240-81fd-2b5c4602640b', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-06-03', null, null, '通常 / 検定準備', '検定問題になれるために、まずは３級（No21 応用５）を実施。最初の３０分で楽々できまいた！ 余力がたくさんありそうだったのと、検定まであまり時間がなかったので。そのまま連続で２級問題へ。最初のサンプル問題にチャレンジしてもらいました。 「〇〇まで聞いて待つ」というブロックを使ったことがなかったためと、最後の修正問題にやや苦戦しており、２級を全部終えるのに50分ぐらいかかりました。', 'スクラッチ歴がそこまで長くないため、２級で今まで使ったことがないブロックが出てくるかもしれないので、類問をたくさんやろうという点に、合意してくれています。 次回も検定準備でOKです。類問を順番に、次は２級のじゃんけん問題でお願いします。', '時間帯: その他
タイピング: ─
盛り上がり: 連続でずっとだったので、ややお疲れモードでしたが。手ごたえはあった様子です。'),
  ('af52c3d3-61b3-5fac-81f8-4fb67efe6318', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-06', '16:30:00', null, '通常 / オリジナル作品の続き〜SDGsで飢餓のゲームを作る', '最初の背景の部分がクリオネが全ての開始になっていたため、可読性がなくなっていた またそのためバグに繋がっていたので、イベントでわけて動作が重なっている部分を分けて考えてもらうようにしました。 ハンバーガーのキャッチゲームを飢餓のゲームとしてやりたかったようなので、昔やっていたことの続きを思い出しながら、なんとかハンバーガーを食べたらスコアが上がるまでを作成することができました。', null, 'タイピング: なし
盛り上がり: 今日は、猫アレルギーのためか顔が痒くなってしまっていて、大変だった感じでしたが思い出せる範囲内で作成できたのが良かったと思います！'),
  ('be7e1913-cd3b-593b-9d41-4f70bb4366f1', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '18:40:00', null, '通常 / 大会準備', '今作っている作品は「ゲーム」モードと「学び」モードの二つに分かれていて、今回はゲームモードに取り組みました。アレンジ大賞の中上級の作品をもとにしたようなゲームを作りました。横移動とジャンプはできました。途中でアイデアが出ず詰まった場合はブレストカードを使う予定でしたが、止まらずに製作を続けられたので必要になりませんでした。', null, 'タイピング: 作品作成続きだったので、いつもやらない寿司打でリフレッシュしました'),
  ('13288e8f-1b87-515d-ab0f-4613b64325ab', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '17:30:00', null, '通常 / 大会準備', 'スプライトの具体的な動きに関してよくわからなくなっていたので、紙に書いてあげながらアイデアを整理していきました。以前やった小技を活用した弾の発射はできましたが、主人公のHPを作るところまではいきませんでした。ゲームの本題からそれて戻ってこられなくなる時もあるので、時々アイデアを書いた紙を定期的に見直してもらうよう、声かけます！', null, '盛り上がり: 細部までこだわりたいという気持ちを感じます'),
  ('602ef468-77df-5656-93a4-9c8d3b1e9a90', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-05', '17:30:00', null, '振替 / 親子大会', '前回まででゲームの概要と背景はできたので、フリー素材を保存してスプライトの用意をしました。素材の量は多かったですが、何の素材を使うかは決めていたようです。 そのあと作成の流れに関して少し話し合い、ゲーム本体を作ってからチュートリアルを作ることに決めました。まずは「スタート」というスプライトを押したら背景を変えるところから始めたのですが、スプライトに文字を入力するなどの作業に慣れていないようでした。そこで方法を教えながらやってもらったのですが、けっこう時間がかかってしまいましたが、最後までしっかり取り組めていました！ 来週は本格的なコード作成に入れそうです。', null, '盛り上がり: 作品全体のイメージはつかめている様子でした。'),
  ('1070dbfb-bfb9-5e6c-b3f1-d5ab206f296f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '17:30:00', null, '通常 / にゃんこ大戦争を最初から作ってみる（https://app.arspark.jp/contents/36070）', '最初は、にゃんこ、太鼓、スラボーからにげろの３っつのゲームを行って、どれが一番自分でやりたいか？を決めるようにしました。 選んでいる最中ずっと、こうなったらいいのに！と１人で叫びながら30分。ゲームのおもしろさを決めるのは自分で少し変更しないといけないんだということをやんわり説明 にゃんこ〜でひとまずアレンジをし、HPの数を増やして遊んでもらいましたが、残り30分で最初から作ってみようということで写経へ。 コード自体は読みこなせているので、集中力との戦いかなと思います。', null, 'タイピング: 以前よりはだいぶタイピングへの取り組み方が変わってきたように思います、
盛り上がり: アレンジをしてゲームを難しくするという考え自体はとても素晴らしいと思いました！'),
  ('96fbd97e-7d4c-5a72-bbfb-06f9178b4cf6', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '16:30:00', null, '振替 / 親子大会用の作品作り', '２週間ほど休んだためかやはり何をやっていたか忘れていた様子。紙に書いていたこともなんとなくしか覚えてない感じだったので、1から作ることに。今の段階では、スタートを押したら人が出てきて、迷子になるというゲームにするそうです。', null, 'タイピング: なし
盛り上がり: ブレインストーミングカードを使用してひろとくんと話しながら、色々なアイディアをみんなから聞いたためか、自分の考えもまとまっていた気がします。'),
  ('880eac45-fccd-5eef-8021-381fb13c0c41', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-05', '16:30:00', null, '通常 / 親子大会用の作品作成', 'だんだんとストーリーが固まってきた様子で、たぬきが旅をして、たまにりんごの木が出てきたら食べる→食べるとHPが復活、食べられないと体力消耗するというゲームを作ることになったそうです。 今日はかんたくんとも一緒にブレインストーミングカードを引いたせいか、アイディアがどんどん追加され、面白いゲームになりそうな感じがしてきました！', null, 'タイピング: なし
盛り上がり: 誰かと対話することでひろとくんの場合はアイディアの質が深まる感じがします。かんたくんととても楽しそうにやっていました！'),
  ('54d0bdbf-f9d8-58c9-b4df-50d88466f662', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '最初の30分くらいスクラッチの脱出ゲームで遊んでしまいました。(一応脱出ゲームのコードは見ていました) レッスン後半は作品作りをやりましたが、やはり内容を見せてくれませんでした。教室のスクラッチアカウントでやっているようなので、こっそり確認することは可能です。', null, '時間帯: その他
盛り上がり: 先生が作品を見るのは嫌がりますが、会話はしてくれます。'),
  ('b1fcd37e-c84a-51eb-8aa2-839625f1d8a7', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / にじいろピンポンの作成を人に教える、にじいろピンポンのアレンジ', '月曜日にレッスンを受けていたせいか、テンションは高めでした。 のあくんに教えることは、とても嬉しそうにやってくれましたが、自分の作成は全くやりたがらず、スプライト、音楽、背景など、どんなアレンジ提案をしても「やらない！」と言い切っていましたが、機嫌が悪いわけではなく、完成したにじいろピンポンに余計な手を加えたくないという感じでした。 ペンの太さを「〇にする」ではなく「〇ずつ変える」にしていたため、ゲームをするたびににじいろが大きくなることに、前半はひたすら面白がって盛り上がっていました。その後、どうしてそうなっているのかを考えさせ、「〇ずつ変える」と「〇にする」の違いについては理解して、自分で修正することもできていましたが、本日の建設的なコード編集はここだけでした。 「ゲームマスターになるには、このゲームをたくさんやってうまくならないといけないから」と主張して、ほぼ1時間集中して、ひたすらピンポンしていました。 終了間際にトイレに立ち、床に寝そべる場面もありました。 今のピンポンが気に入っているなら、次回は他のゲームを作ろうね、との誘いにも、「ゲームは作るんじゃなくてやるほうがいい」と言っていましたが、基本、反抗しているというよりも反射的に否定の言葉を言っているだけで、機嫌は終始良かったです。', null, '時間帯: その他
タイピング: のあくんに画面を見せたりしながらやっていました。
盛り上がり: ほぼ授業にはなりませんでしたが、のあくんに教えるのは得意げにやってくれ、適当なゲームで遊ぶのではなく、ひたすら自分の作品をいじり倒した集中力は、ある意味すごかったです。'),
  ('79f15507-51f3-555c-9547-5792633b38e6', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 虹色ピンポン', '最初は先週同じものを作ったこうしろうくんに教えてもらって作る予定でしたが、こうしろうくんはゲームのアレンジとプレイに夢中になってしまったため、動画を見ながら作りました。写経に近い感じではありましたが、少し作るたびにコードの意味を説明しテストプレイしてもらうことで、コードと動きの関係をつかんでもらうようにしました。ちょうどレッスン時間の終わりくらいで完成しました。ブロックを探すときに「このブロックは「せいぎょ」のところにあるよ」などと言っていて、何回か使ったものは覚えてきていると思います。ただ、「～にする」と「～ずつ変える」を間違えることがあるので、近いうちに違いを理解させてあげたいです。', null, '時間帯: その他
タイピング: こうしろうくんと仲良く並んでやっていました
盛り上がり: 動画を見せると興味を持って作成に取り組んでくれました。表情は少し硬いのですが、楽しんでいても表情の変化はあまりない子とのことなので大丈夫そうです。'),
  ('c0a9b188-5365-55a7-86d3-e9e09849c2e5', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', 'オリジナルの片づけゲームを作成しています。 ゲームが始まったら、部屋に散らかっているものをクリックして所定の位置に戻すと褒められる、という仕様なのですが、ボールのスプライトをクリックしてもマウスについてこないと悩んでいました。 どこが問題なのか、どこから手をつけていいのか、完全にわからなくなっていたので、少しずつコードを確認していく手順を一緒にやりながら教えました。 ①ボールスプライトをクリックしたらマウスポインタについていく、というコード自体の正誤を確かめるため、そのスクリプトだけをクリックして動かせることを確認しました。 ②スクリプトが合っているということは、他に問題があるということで、緑の旗を押した後の該当箇所で、複数のスクリプトが実行中の状態になっていることを確認しました。実行中のスクリプトの中で、ボールスプライトの位置に干渉しているブロックがないかを探させ、ゲーム開始時に表示させる座標のブロックが実行中のままになっていることに気付かせました。 ③スクリプトを実行させるタイミングが本当にあっているのか、繰り返したいブロックと繰り返してはいけないブロックはどれか、迷ったらそのブロックを丸ごと削除するのではなく、少しずつ外して動作を検証していくことをやってもらいました。 以上の手順で、とりあえず今日の問題は解決できたようでした。 上記が解決した残りの時間は、音楽などの素材を探していました。', null, '時間帯: その他
盛り上がり: 問題が解決できたことは、とても嬉しそうでした。 コードの方ができてきたので、その後は素材探しをしていましたが、PCについての雑談などをだいきくんに持ち掛けたりと、楽しそうにしていました。'),
  ('fb44e13b-25df-51bc-bc9a-67ba54df81b2', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '「敵の体力を作りたい」「敵を一人倒したら違う場面に移したい」ということを積極的に伝えてくれました。変数を使う必要がありましたが慣れていないようなので、変数の値を変える方法、変数の値による条件分岐の方法を教えました。また場面転換に関しては、メッセージを使うとできるというヒントを出すとできていました。メッセージはこの作品内でもすでに一度使っており、マスターしているようです。', null, '時間帯: その他
盛り上がり: ときどきあおしくんに作品を見せていました'),
  ('16460156-625d-5d6e-b778-fbd683debf0f', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', '素材を集めることがメインの回が続いたので、今日は素材はほどほどにして少し作成を進めつつ、追加したい素材を考えていこうと促しました。 改めて、どんなゲームにしたいのかを話し合い、素材を集めて家などを作るゲームにしたいということを確認しました。 プレイヤーキャラクターは、既存のスプライトではなく少し凝りたいようだったので、とりあえず説明役のキャラクターを決め、オープニング画面を作成しました。 ゲームの仕様を考えるため、作りたいアイテムと必要素材を書いてもらおうとしましたが、紙に向かうと考えがとまってしまうようだったので、実際に作成しながら考えるスタイルに切り替えました。その方がイメージがわきやすいそうです。 素材がいくつ集まったかどうかわかるようにするためにはどうするか、の発問で、変数を使うことに気付き、素材獲得数用の変数を作成していました。', 'マイクラのイメージが強く、そこをこだわり始めると作成が終わらなくなりそうなので、完成までのスケジュールをたててあげるとよいかと思われます。', '時間帯: その他
タイピング: 地道に毎回きちんと取り組んでいます
盛り上がり: マイクラのようなゲームを作りたい、ということは一貫していて、こんなゲームにしたいと語るときはいつも嬉しそうにしています。 画面上の桜の木などが素材になる過程や、アイテムを獲得するための手持ちの道具など、こだわりたいところが色々あるようでした。'),
  ('0187c2e0-9264-5138-998c-c8659d013e95', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-06-03', null, null, '通常 / 親子大会', '先週でゲームの流れはイメージできているらしく、ストーリーを作っていきました。平和な世界→敵が現れる→戦闘画面に移行 という順番で進んでいて、戦闘になると背景やBGMも変えたりしていて、世界観がよくできていると思います。ただ、「〇回繰り返す」の中に「ずっと」が入っているためバグになると思うので、来週はそこを対処したいです。', null, '時間帯: その他
盛り上がり: 長いコードも出てきていますが、集中して作れています。'),
  ('ca435b62-45aa-5420-a9ce-6bd7415bf0d3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-03', null, null, '通常 / コンテスト作品の作成', '前回作成したクローンを使ったジャンプが嬉しかったようで、タイピングを飛ばして楽しそうに動かしていました。 プレイヤーを矢印キーで動かしつつ、背景も一定の速度ではなくプレイヤーの動きに合わせて動かしたかったそうですが、さすがに今のゆうかちゃんのキャリアではとても時間がかかり、肝心のアレンジまで手が回らない可能性が高いことを伝えると、背景を順次切り替えていく方向に切り替えてくれました。 今日は背景まわりの作成をすることを目標に、オープニング画面と複数のステージを作成しました。メッセージ機能のよい復習になりました。', '背景を切り替えるメッセージまわりの完成と、ブロック上でのジャンプ部分の作成', '時間帯: その他
盛り上がり: 前回、前々回は、やりたいことと現状のスキルが合っておらず、ゆうかちゃん自身もかなり混乱しているようでしたが、今日で少し見通しがたってきたのか、久しぶりに楽しそうに作成をしていました。'),
  ('6cd7d560-a9bc-5fba-a08d-1d3145a985fa', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '18:40:00', null, '通常 / 虹色ピンポンのアレンジ', '最終的には２Pで遊ぶゲームになりました。 ちゃんとゲームのクリアまで考えられ、隠すや表示、もし〜、ずっとなどはかなり定着した様子が伺えました。 演算を２つ組み合わせて使うやり方を今日は教えたのですが、どう重ねるか？というところで何個も重ねてコードが書けるということにとても驚いていました！', null, 'タイピング: なし
盛り上がり: ボールの色の変更、音へのこだわりがあることがすばらしい！'),
  ('a48f6792-2bbd-5bc3-95e9-b15d836f52fa', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '17:30:00', null, '通常 / 今日はピンポンゲームのアレンジ', '戦闘機が邪魔するというアレンジにしたかった様子でした、戦闘機が当たったらゲームオーバー。 今日はちょっとお疲れモードだったので集中力に欠けていましたが、なんとか最後まで自分がやりたいことができたようでした。', '来週はゲームオーバーまで作成するといいのかなと思います', 'タイピング: なし
盛り上がり: 自分がやりたいことをちゃんと言えることはとても素晴らしい'),
  ('d6194733-aa23-57f6-b1d7-d608b4405e14', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-06-02', '16:30:00', null, '通常 / オリジナル作品を作成し始める', '最初はアイディア出しから始めないといけなかったのでブラインストーミングカードを引いてもらい、開始しました。おじいさんおカードから杖をイメージ、村人が助けて〜といって杖を持ったあるくんが助けに行くというストーリーになるそうです。', null, 'タイピング: なし
盛り上がり: カードをひいた後に頭の中で色々な想像をしたようです。 創意工夫をする部分に関しては、とてもいいなと思いました！'),
  ('88f6e600-3bda-51e5-800b-2914c46456f9', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-02', '17:30:00', null, '通常 / 大会作品続き', 'ゲームの内容に少し困っているようでした。晴くんの太鼓の達人の作品をみて、リズム系のゲームにすることを決めたようです。落ちてくる矢印に合わせて矢印キーを押し、音がなるようなプログラムを作成しました。 最初、位置座標でプログラムすることを考えましたが、あたり判定がシビアでうまくプログラムを動かすことができませんでした。アイデアとして、「半径●以内であれば」ということ提案しました。うまく動かすことができたので良かったです。', null, '盛り上がり: いつもより少し疲れていて他のことに気が取られてしまう印象でしたが、晴くんと話したり最後に作品で遊んだりして、楽しく取り組めていました。'),
  ('3ed7da6f-ed70-5e70-9760-f6254f3a5943', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-06-02', '17:30:00', null, '通常 / 楽しく取り組む（ビーム、太鼓の達人など）', 'ビームは一度やったことがあるようだったので、太鼓の達人に取り組むことになりました。「今日はこれをしないといけない（何かしなければいけない）」といって、進んで取り組めていました。コードを移すことになってしまいましたが、音楽を自分で持ってきて少しずつ確認しながら楽しくできている様子でした。太鼓が出てくる回数を増やしてボーナスタイムを作り、作品に工夫ができていました。 授業最後には自分が作った作品を遊んでもらえて嬉しそうな様子でした。', null, '盛り上がり: しっかり集中して頑張れていました！すごい！！'),
  ('f6622d33-3ab0-5322-9d88-9f52a87f679e', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-06-02', '18:40:00', null, '休み（未対象）', null, null, null),
  ('393a3286-4578-5100-afa5-4597039d2e4b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-06-02', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('4cd6fb2d-bc06-58c6-a1e4-27e6380ca8f6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-06-02', '17:30:00', null, '休み（未対象）', null, null, null),
  ('f61aa1f2-65c9-5c1b-a431-3a545fd6ee67', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常', '前回うまく作れている思った寿司屋のゲームをカオス化していきました。カオスになる前の品名の表現や色のグラデーションはほかにみないまさき君のいいところなので、そこもう少し伸ばせば、いいコンテスト作品になりそう。 この後にも、トイレのゲームや背景だけを高速で変えて、ストップモーションみたいな感じなものも抱け上がっていたので、表せる表現は凝ったものに上がっています。', null, '盛り上がり: 最初の寿司屋の自慢は元気良すぎました。'),
  ('c89af1ce-8afe-5969-b1b5-8d3bc02e760f', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常 / 大会作品作り', '今回はコスチュームの選びがメインとなっていました。ただ、いらすとやから持ってくるだけではなく、自分好みに変化させて、いいこだわりを持ています。テキストの表現もあった手若干の切なさが伝わってくるがまた良かったです。画面切り替えで幽霊の効果を使っていたが、変わっても効果が切れてないので、効果を消すかマイナスに幽霊に効果を使うか下上げた方がいい', null, 'タイピング: 指さばきがすごいです'),
  ('c3b3dc76-74ea-5e6e-a9d7-50cdfe429eb6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-01', '17:30:00', null, '通常 / コンテスト作品の作成', '自分への自信や作成意欲に多少波がありますが、途中まで公開したストーリーがScratch上で反響があったこと、作画？を頼んだ相手から、テキストの内容と表示の仕方でとても完成度が高く、下手に手を加えなくても素晴らしいと評価されたことが嬉しかったのか、作品を完成させようという意欲は湧いたようでした。 ストーリーのテキストをすべてコスチュームで作成しているため、容量を心配していましたが、テキストの表示方法を凝るところはここぞというときにしてみたら、等の意見には納得していました。', 'お話自体は力作かつ自信作のようなので、テキスト以外の見せ方の部分の工夫をしていきたいところです。', '盛り上がり: 作品途中経過に対し、大量のコメントが来ていて、概ね好評だったことで、モチベーションは上がったようでした。
備考: 個人のScratchアカウントで作成しているようなので、次回IDを聞いてインポートできるように環境を整える'),
  ('6c27ede9-850b-5384-aaba-964a75fc09ac', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '17:30:00', null, '通常 / ビーム、ゾンビを倒せの復習とキャッチゲームの作成', '最初に、ゾンビを倒せで作ったところの復習をしていきました。ゾンビはどこでどう動いていたか、ビームをどうしたら何発も打てるようになったのか確認していきました。ビームのところは最初作った時は一発のみだったことは覚えていたが、あやふやだったので動画を見返して、仕組みを再確認していきました。最後に、少しのアレンジとしてビームの形を特大のビームに変えて、どこでもあたってしまうようなビームに代わりました。その変形はかずま君自身が楽しんで、コスチュームの複製の仕方など新しく知れたこともあったのでいいアレンジだったと思います。（下迫田） ボールキャッチゲームは、スプライトをたくさん並べたところで燃え尽き感が見られましたが、残り時間があと15分だったため、キャラクターの左右の動きだけ作成して終了という約束をして取り組みました。 キーで左右に動かすには、「スペースキーが押されたとき」ブロックを使うということはすぐにできていて、その後、マイナスを使うんでしょ？との発言があったため、ゾンビを倒せで使ったx座標を〇ずつ変えるの動きは覚えたようでした。 使用しているスプライトがバスケット選手だったので、座標を-〇ずつ変えるだと、後ろ向きに動くのを確認させ、向きを変えるために「〇度に向ける」ブロックを使うこと、スプライトがさかさまにならないように、体験で使用した「左右のみ」のブロックを使うことを教え、実際に違いを確認させたところ、オーバーリアクションで感心していました。ここまでで10分前を切ったため、次回は続きを作ることを予告して終了しました。（大原）', null, 'タイピング: 新しいキーをちゃくじつにおぼえていきます'),
  ('eceae4bb-0b0f-58ed-b4b4-039d311c42da', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-06-01', '17:30:00', null, '通常 / ・前回のチーズを探せの動作確認、乱数を使ったランダムな回転をするか、本人次第（前回は、好きなように動かして満足していたので） ・コンテストの動画視聴、コンテストの説明と構想', '最初にコンテストの説明をして、昨年優秀作品の動画視聴をしました。動画自体はそれなりに興味を持って見ていましたが、「コンテスト」のイメージはあまりはっきりしないようでした。それでも、オリジナル作品を完成させてみようというテーマには喜んでいました。 どんな作品を作ってみたいか、という話を始めてすぐに、「やってみたいことがある」と言って、スラスラと作りたいゲームについて話してくれました。 ・所持金があって、買い物をしていくゲーム ・買い物リスト、または目的の料理があってその材料を買っていく ・買い忘れがあったり、違うものを買ったり、予算オーバーをしたらアウト ・同じ食材でも、適度にセール品を買わないと予算オーバーする仕組みにする 今日浮かんだゲームのイメージはこのような感じで、それを紙に書きだしました。作りたい料理候補はカレー、焼き肉、デザートを挙げ、それぞれに必要な食材を家で確認してくるとのこと。 いらすとやで店内の背景や食材の画像をダウンロードして、アップロードしました。', '素材集めが終わったら、ゲームの仕様をもう少し明確にして、コード作成に入る', '盛り上がり: 似たようなゲームがアルスパークになかったこともあり、とても生き生きと「こんなゲームにしたい」と語ってくれました。 はじめてのオリジナル作品で気分も盛り上がったようで、いつもよりも積極的に意見を言ってきてくれました。'),
  ('d8f120d8-aae8-53a6-a73b-eafcb32319f1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-06-01', '16:30:00', null, '通常 / 大会作品作り', '今回は前回話題に上がった公園の写真を取り込んで、敵ごとの背景選びをしました。それぞれの敵たちにあった背景を選んで、それぞれ紙にメモしながらやっていました。そして、最初の対戦のへー減のバトルに作ろうとし始めた時、スプライトが画面上にたくさんあったのでの初めの段階で隠すように提案してみたら、メッセージのやり取りでうまくコードで作れていました。ほかのスプライトのへの作成もバックパックを利用して起用に作れていました。主人公のHPとヘーゲルの攻撃の絵をかけたので、次回はその動かし方を作って、3，4体の位の動きは作りたいです。', null, 'タイピング: 検定の順位がっ少し下がっていて悔しがっていました
盛り上がり: 背景の選定はいいリアクションしながら選んでいました。'),
  ('94fadc8d-3200-5cfc-b3f4-2a8641460d4d', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '17:30:00', null, '通常 / 大会作品を作ろう', '今日はオープニングつくりをしていきました。敵役の登場に斜めに登場したいとアイデアを出してくれたので、とりあえずこの通り作ってと言って三角関数を用いて表現してもたら、めっちゃ喜んでくれました。セリフのやり取りの際にメッセージ使ってみたらと提案したら、特に迷うことなく作れました。アイデアがどんどん出てきたので、今まで1番コミュニケーション取りやすい感じにできました。助言程度で作っていき、時間の間の取り方などを教えていけました。コードのセリフや出現のやりとり順番に少し不安を感じるので、そこは支えていきたいです。', '敵を去っていた後の対戦の作成', '盛り上がり: 敵役の登場の仕方を作ってから一番喋れたように感じました。'),
  ('e6c6169d-1cae-524f-885e-78b55ac86066', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '16:30:00', null, '通常 / 大会作品を作ろう', '今回は主にオープニングつくりをメインに作っていきました。背景に文字の大きさに調整するのが若干時間がかかってしまいました。背景とスプライトの出方の順番に苦労していましたが、きれいに整えることができました。 次に、飢餓のゲームとして落下ゲームのとして食べ物を集めていくようにしていきたいそうです。カードを見ながら作成していったのでそこは問題なく進められそうです。', null, 'タイピング: 2秒後半の打鍵速度は良かったです'),
  ('a12fda76-dfde-5da1-bd2a-7c45c4a5a5a6', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '17:30:00', null, '通常 / 大会準備', '前回の続きをしました。得点などのプログラムを作っていました。棒人間のコスチュームにアレンジを加え、敵っぽい要素を出していました。 対戦ゲームになる様子ですが、ストーリーが思い浮かばず、後半はかなり苦戦していました。ブレストカードを使ってみましたが、それでもアイデアが浮かばなかった様子です。ふとした時に思い浮かぶと思うので、来週までになんとなく考えてくるようにお願いしました。', '今回はタイピングを見送りましたが、かなり苦手意識がありそうなので、大会準備中とはいえたまに取り組む必要がありそうです。', null),
  ('6e1a2898-b830-58cb-a82a-c82a6c5fef7f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '17:30:00', null, '通常 / 大会準備', '前回まで作っていたものはお試しだったようで、今回から本格的にプログラミング大会にむけて準備を始めました。最初はマリオのスプライトを使ってプログラムを始めていましたが、使えないことを伝えると、他のスプライトを使ったり、ストーリーを変えたりして柔軟に対応できていました。 移動手段として車を使い、バトルするゲームになるそうです。スプライトを丁寧に作っていました。次回から本格的にプログラムに入りそうです。', null, '盛り上がり: とても集中して取り組めていました。'),
  ('d5dcf362-8032-5591-94fa-08d7078beacf', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '16:30:00', null, '振替 / 大会準備', '前回の続きからプログラムを始めていました。全体的にバグをつぶしながら丁寧に取り組めている様子でした。背景の明るさを変数でコントロールしていて、新しい考え方でよいと思いました。プログラムの書く場所、メッセージを使う必要性についてすこしアドバイスをしました。背景がうまくコントロールできないときがありましたが、プログラムの事項順序を確認するように伝えました。うまく対応できたようです。 プログラムがうまく働かないときに、自分なりに仮説を立てて取り組めているので素晴らしいと思いました。一人でバグに立ち向かうのは寂しいし詰まるので、他の人を頼るように伝えました。', null, null),
  ('b572406a-0b09-5536-af5d-f17115041239', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-30', '16:30:00', null, '通常 / 簡単なジャンプのさせ方を学ぶ', '1の内容は前回とほぼ同じだったので、復習を兼ねて自分で作ってもらいました。「〇回繰り返す」こそ思い出せなかったものの、キーを押す、条件分岐などの考え方はしっかり理解してくれていたようです。 その後、あるくんの冒険2に挑戦しました。今回が初のレッスンでした。ビデオをよく見つつ取り組むように伝えましたが、自分では見切れない様子でした。答えがもう提示されてしまうと面倒になってしまう傾向があるようです。 色によってジャンプをコントロールすることを伝えました。なんとなく理解できたようで、最後は自分の作品にも取り入れていました。', '今日やった内容を大会にも生かせればなと思います。', 'タイピング: ミスタイプ2％、はやさ1.3 タイプ/秒 とても集中して取り組めていました。
盛り上がり: 集中して取り組めていました！'),
  ('07d3b3cf-6f1e-5607-9959-a8f94e7a834b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-30', '16:30:00', null, '通常 / レインボーピンポンを完成させよう', '前回に続いて虹色ピンポンを作っていきました。説明書を見ながら、ここまで作ってみようねと教えながら、作ってみました。前回よりは先生のくっつりより少し弱くなったかもしれませんが、作業が終わると町の時間が発生していました。このコードを作ったら何ができたか質問して、大切さを重用しました。打った回数や虹色の軌跡を作ったら、目新しいものが感じられて、喜んでいました。これでひとまずは完成したので、その後のアレンジとして、ほかのスプライトを何体も用意して、当たったら消えるようにしたいそうです。', null, 'タイピング: とりあえずキーを押してしまう感じが多いです
盛り上がり: いったん出来上がった時はとても喜んでいました。'),
  ('33e41b84-6916-565f-9171-396c15ec31e0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '18:40:00', null, '通常 / オリジナル作品作成の続き〜', '最初の画面（チュートリアルの部分）でボタンを押したら次の画面に行く〜というところで戸惑っていましたが、はるちゃんの作品を参考にしながら「あ、そっかそんな簡単なやつでよかったんだ」と思い出してもらいました。 途中、壮大なゲームになりそうな予感がしたので。はるちゃんのように開発画面のボタンをどこかのタイミングで作った方がよさそうだね〜という話もしておきました。 終始自分の作品を作ることに楽しんでいたようで、わからない部分を私に聞きながらものすごい集中力で行っていました！', null, 'タイピング: なし
盛り上がり: 色々なアイディアが作成中に出てきているかんじ。やはり手を動かしながらの方がげんきくんにとってはあってそう'),
  ('1e743d91-bd71-58d3-97b5-3f3a945ea2c4', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '16:30:00', null, '通常 / 虹色ピンポンを最初に見て、コードを読み込む→その後にオリジナル作品の続き', '虹色ピンポンでは、ペンツールの部分を再度おさらいしました。 残像もペンツールで一応スタンプという機能を使ってできるんだよ〜ということをおさらい（割と忘れていた部分ではあったみたい）色の変化などもどうしてそうなるのか？をもう一度考えてもらいました。 その後、もう一度オリジナル作品を文章ではなく、絵コンテで作成（文章だと読み込む時間がかかるという話しをしながら） 実際にはバトル系で、難しいモードと優しいモードを作り、優しいモードの時にはタイミングを見計らってヒントがでるという仕組みにしたいそうです。→ここリストか、変数をつかわないといけないかな。', null, 'タイピング: うでだめし →タイピングの速度がかなり上がってきました。うでだめしをしたのはとても大変だったようですが、力がついてきているので、本人も結果に満足していたようでした。
盛り上がり: 絵にすることで自分のやりたいことがもっと精査された様子。スプライトのキャラクターを自分なりに好きなものにしたいということ。なので、来週までに検索してもらい良いキャラクターのコスチュームがあったら、LINEで送ってもらうことにしました。'),
  ('eee47a03-1df1-5826-a39a-b7b65986c7b8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-29', '17:30:00', null, '通常 / 大会準備', '授業前からショップや掲示板を作ってすでに始めてくれました。浮島も作成してくれていました。自分の王国を悪役から守るイメージ（ゼルダリスペクト）だそうです。「最背面にする」のブロックを紹介しました。 たたかいのプログラムを先に取り組むようにアドバイスしましたが、本人はショップに置くものや見た目の方が気になるようで、先にそちらに取り組むことにしたようです。 いくつかのステージがある長めのプログラムになるようです。「難しい」と言っていましたが、最初のステージだけとりあえず作り、その後考えるようにすすめました。本人もスプライトの多さにびっくりしていました。コスチュームを変更することで対応できることも紹介しました。', '詳細をまた考えてくるようにお願いしました。', '盛り上がり: 悩みつつもしっかり手を動かせていたので良かったです。'),
  ('07728353-e974-5c7f-b5ab-547f449e7dcc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-29', '16:30:00', null, '振替 / プログラミングコンテスト、虹色ピンポン（ちょうど題材的に教科書の09 ピンポンと同じだったため）作成', 'レベルを２アップして今日はやるよ〜と伝えました。 約束事として ・のあくんに来週この単元を教える をテーマにしてやったので来週はその調子でくると思います。 完成まで終わり、自分で動画をみて完成させた達成感は感じていたようでした。 「覚えているんだけど、忘れてしまった」という場面がいくつかあったので、本人にも刺激になったようです。', '今回の作品をアレンジでもいいし、もしくはのあくんに教えるという感じでも。 お母さんにはコンテストの作品を作成したよという話を伝えて、大会に出すと意思があれば出しましょうと伝えています。', 'タイピング: なし
盛り上がり: 自分で作り上げた達成感がとてもあり、またレベルアップしているんだ！という自信がついたようです。'),
  ('1ac3dc27-3145-5a56-a231-61984fe98a3e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-05-29', '17:30:00', null, '休み（未対象）', null, null, null),
  ('414ea1f4-d666-511b-bdc3-ab87386b08ca', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '17:30:00', null, '通常 / オリジナル作品の作製', '黙々と作っている。温暖化やSDGｓについて調べている様子。作品は見せてくれない。 最初珍しくScratchのゲームで遊んでいたので注意。', 'オリジナル作品の続き。', 'タイピング: なし
盛り上がり: 本人が言うには、作品は順調に進んでいるとのこと。
備考: 作品を見せてくれないので、本人にわからないようにどこかで内容の確認が必要。'),
  ('d69e074d-009e-5256-9870-01fd8e34ac2d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '17:30:00', null, '通常 / オリジナル作品の続き', 'オリジナル作品の作製。自分でフリー素材を見つけて使ったり、音声作成ソフトを使ってオリジナル音声をつくっていた。著作権について自分で調べたり意欲的だった。 クリアのスプライトの作製、片付ける対象のスプライトのプログラミング（ここがうまくいっていない） うまくいかないプロぐラミを直さないまま、他のことに取り掛かってしまう傾向あり。 一度立ち止まって自分の作ったプログラムを見てみる時間があるとよいと思う。', 'オリジナル作品の続き', 'タイピング: なし
盛り上がり: 自分で作る調べるのは大好き。黙々とやっている。わからなければ質問してくれる。'),
  ('c9e09e2c-f9ba-5d73-bcea-89c29c1dc44e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '16:30:00', null, '通常 / オリジナル作品の作製', '最初はスプライトの色を変更していました。集中力が切れることもありましたが、湊太君を見てやる気を取り戻し、 スラぼうが話す⇒魔法使いが近づく話す まで自力で作っていました。', 'オリジナル作品の続き。一回何をやりたいか聞いてから始めたほうがいいかもしれません。', 'タイピング: 新しい項目にチャレンジ 順調
盛り上がり: 湊太君が良い刺激になっていて、集中力が切れても湊太君がしっかりやってるのを見るとやる気を取り戻します。'),
  ('6b2347ab-d47d-585f-9c1e-4abad1bba3ea', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-27', null, null, '通常 / プログラミング大会の作品作り', '前回は、作業が全く出来ていませんでした。 今回も、手が動いていなかったので、こちらがお題を渡して作業を行っていました。 中々うまいアドバイスが与えられなかったので、次回までに良い対応が出来るよう頑張りたいと思います。', '引き続きプログラミング大会の作品作り', '時間帯: その他
タイピング: 問題なく出来ていました
盛り上がり: 背景作りを頑張って作成していました。'),
  ('0864de36-a950-56e0-88c2-a35ac2a03033', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-27', null, null, '通常 / 親子大会のアイデア出し', '使いたい素材がたくさんあるとのことで、それらを紙に並べて書き、整理してもらいました。そのあと前回と同じように素材となる画像を集めていきました。自分で描いた画像やフリー画像のサイトからダウンロードした画像をスプライトとして取り入れました。しかし素材が多すぎるとプログラミングに手が回らないと思われるので、ある程度のところで切り上げてゲームの全体像を考え、コーディングに入ってもらおうと思います。また、3Dだと技術的に厳しそうなので2Dに誘導していきます。', '次回以降、画像を使うときはGoogleドライブの「生徒」フォルダに入れる', '時間帯: その他
タイピング: 集中していました
盛り上がり: 作業がゆっくりめのペースではありますが、モチベーションはあると思います。'),
  ('26a8294a-541c-5334-ae4f-0146c66924f3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-05-27', '16:30:00', null, '通常 / オリジナル作品の作製', 'オリジナル作品の続きを作成、以下項目を追加。 １，最初に敵キャラクターを隠す ２，ボタンを押すと敵キャラクターが出現する ３，盾を作って押すとシールドが出る ４，敵キャラクターが出現したときにHPを表示する 敵のHPを表示するために新しく変数を学びました。 変数は箱で数字や文字を入れることができることを説明、関連ブロックの意味を説明。 次回変数に関しては軽く復習してあげてください。', '変数の復習をし、その後オリジナル作品作りの続き。 おそらく今日の話だと次は敵と戦えるようにしたい感じです。', 'タイピング: 新しい項目にチャレンジ 順調
盛り上がり: アイディアをしっかり形にできて嬉しそうだった。葵史くんをいい意味で意識して作品作りに取り組んでいた。'),
  ('601e448f-af5d-50cb-8bae-0ecc4586d7f6', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-27', null, null, '通常 / 今後取り組む課題の決定、計画', '全国小中学生プログラミング大会の説明をしたところ、興味があると即答しました。第7回大会と第2回親子プログラミング決勝大会の動画を視聴してから、なんとなくアルスパークを触りつつアイディアを考えたいとのことでしばらく自由時間としました。 当初は謎解きのようなゲームを作りたいと言っていましたが、アイディアに詰まってしまい、ゆき先生とブレストカードを使って話したりしているうちに少し展望が見えてきたようでした。', '3級の検定問題を一度やって感覚を思い出し、余裕があれば2級に挑戦', '時間帯: その他
盛り上がり: コンテストを紹介したら嬉しそうにしていました。いきなりの提案だったせいか、かなり考え込んではいましたが、コンテストに出したいという意志は強く、最後までやる気は見せていました。検定についてもやる気十分で、コンテストと両方やる！と言い切っていました。
備考: 【ユーザー視点から考えること、作成することを重視！！】'),
  ('1e945b8e-90e9-5557-af22-3e01e58250e3', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-27', null, null, '振替 / プログラミングを楽しむ', 'ロボットの振替なので、楽しんでもらうことを前提にしました。事前に教材の目安はつけておきましたが、本人が体験のときの洞窟ダイヤアレンジが楽しかったのを覚えていて、同じようなことをやりたがったため、好きなゲームを選んではゲームバランスが自分に合うように変数やスピードの数値を変えたり、音を変えたりするアレンジを繰り返しました。 ＜使用ゲーム＞ 【Prg】初級 計算ドリルを作ってみよう！ 【素材だけシリーズ】カーレースゲームを作ろう！ にじいろピンポン メッセージ無しアイテム脱出ゲーム', null, '時間帯: その他
盛り上がり: 1時間飽きずに楽しそうに取り組んでいました'),
  ('9d699409-becb-55ac-9342-41860f9868ae', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '16:30:00', null, '通常 / 大会準備', '30分ほどで作品の大枠は完成しました。その後、うった数の変数を設定し、クリア画面を作っていました。丁寧に作業できていました。 最後に、時間によってボールが動く速さが変わるアレンジを追加しました。大枠は自分で考えられていましたが、演算の使い方とブロックの置き方がイマイチだったので、一瞬しかプログラムが動いていませんでした。「もし～でなければ～」のブロックを使った方法を紹介しました。理解はできている様子でした。', null, '盛り上がり: 来週から本格的にオリジナル作品に取り組むことを伝えました。 自分の作った作品を楽しくプレイできていたので良かったです。'),
  ('dde8231b-f883-5ca3-a1ad-ee82ca444b20', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '18:40:00', null, '通常 / 大会準備', '対戦がテーマとなりましたが、具体的な作品のアイデアがなかなか思いつかなかったので、カードを使って考えました。いくつか弾き、宝探しとなりました。スプライトに帽子をかぶせたり目をつけたりして、自分なりにアレンジできていました。 左右に動かすときに角度の話をしました。動く前に動きたい方向に向くようにアドバイスをしました。敵などのスプライトを登場させました。手裏剣が回るようにプログラムしたかったようですが、角度にあまり気が付けなかったので残念でした。', null, '盛り上がり: 空中にとどまらないように色を使ったプログラムを共有しました。ジャンプしたときに茶色にめり込んでしまうことが今後の課題です。'),
  ('a627721f-497f-54ab-b93f-687b9f4efa98', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '18:40:00', null, '通常 / プログラミング大会中学生の部の方に提出することに一旦し、時間があるためすこし考えるペースを多めにしながら作っていきたい。', '最初は何を作ろうか？と中学生部門の最終選考のyoutubeを見たせいか悩んでいましたが、ブレインストーミングカードで考えて箱を選んで、ゲームと学びの感じのオリジナル作品にすることに。箱の設定など最初のコマを今日は作成した感じなので次回からは、層を深くするのをどこまで書くか？をどんどん決めていければいいかなと思います。', '作品作成', 'タイピング: なし
盛り上がり: 自分でどういう作品を作ろう！と決めた時間からはサクサクと指が動いていたので目標を一つ決めると早いなぁと思いました！'),
  ('899ba47e-09b1-5c27-840d-64707eab8762', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '17:30:00', null, '通常 / オリジナルに挑戦', '懐中電灯の小技やきれいな残像の小技をやってみるように促しましたが、「いやだ」の一点張りであまりやってくれませんでした。大好きなホラーアニメがあるそうで、それに関連した作品をやってみたいようでしたが、「難しいしできない」としょっちゅう言っていました。最後は、描画機能で遊んでいました。', '来週以降は、アルスパークのレッスンのアドバンスかエキスパートに挑戦し、30分でもいいので取り組み、基礎を確認していく予定です。', null),
  ('97f6dc68-e6b1-56e4-8bfb-72d933d62ee7', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-26', '17:30:00', null, '通常 / オリジナル作品(前回楽器演奏)', '前回作った楽器を参考にして作品を作るようです。音が鳴ったのと同じようにしてキーをたたいて、音楽でバトルゲームを作りたいそうです。今日はゲームが始まる前の説明のプログラムを作成していました。説明の言葉がかなり長かったのですが、辛抱強くタイピングできていて良かったです。 たたいたキーの順番を判定するプログラムが必要になってきそうです', null, '盛り上がり: 集中して取り組めていました。'),
  ('cec3b066-bdf6-571f-beaf-8a9500e2785e', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '18:40:00', null, '通常 / プログラミング大会 ビギナーズ部門のアレンジから作成してみて、オリジナル作品に移行してもOK', '最初はオリジナル作品を作ると話していましたが、やはり行き詰まり、ちょっと遊んでいる感じになってしまったので、一旦ビギナーズの方でピンポンを作って、そこからアレンジになりました。アレンジをどうするか？の部分ではボールを2個増やすまでやってみると話していました。', '一回アレンジまでやってみて、そこからオリジナルでできそうだったらやってみるという、ピンポンを一旦安牌の部分においてみました。', 'タイピング: なし
盛り上がり: 虹色までできた時にとても嬉しそうでした！'),
  ('d25b3ff8-01db-5258-afb5-c44247cce8ed', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '16:30:00', null, '通常 / プログラミング大会のオリジナル作品を作成', 'コインが自動的に落ちてくる作品（以前なんでもつくっていいよーと話していた時の作品の続きからみたいな感じ） コインが落ちてくる＞爆発＞クローンが止まる＞泥棒が出てきたら対戦をする という内容で、クローンが止まるという部分までが完成しました。 途中変数とメッセージが干渉し合うようなプログラミングを作ろうとしていたので色々とアドバイスをし、バグを潰しながらクローンが止まるまで作成しました。', '次回は対戦の部分を作成', 'タイピング: なし
盛り上がり: 自分の作品がちゃんと作動すること、コードが長くなったらどんな弊害が出てくるのか？を今日はちゃんとつぶせてできたので、満足した感じでした'),
  ('a5d1f4cd-ecbc-5fb9-a68d-47c3bec678af', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-05-26', '17:30:00', null, '通常 / アレンジ大会 ビギナーズ部門（https://www.802p-oyakotaikai.com/%E9%83%A8%E9%96%80%E7%B4%B9%E4%BB%8B/%E3%83%93%E3%82%AE%E3%83%8A%E3%83%BC%E3%82%BA%E9%83%A8%E9%96%80/） の作成から', 'お手本Youtube動画を見ながら一緒に作成、10:38秒目まで一緒に行いました（ボールがボタンに触れたら跳ね返るまで） 結構な集中力で45分間一生懸命やっていました。 動画を見ながら作成することで集中したのでしょうか、解説を見ながらやることでちゃんとそういう動きになるのか！と感動していたようでした。', '10:38秒目から完成、アレンジまで', 'タイピング: ココアははじめのラウンド２まで、子供タイピングは4個ぐらい、少しずつだけどタイピングできる数が増えてきました
盛り上がり: 説明を聞き、動きが実際になることでとても満足していた様子でした。'),
  ('a25d4df0-eca6-5aad-aa90-7d704439d99e', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-05-26', '16:30:00', null, '休み（未対象）', null, null, null),
  ('e6f1bbed-3d2a-59e8-9894-7bec6a7f9e0e', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', 'オープニングを一生懸命作っていました。 キャラクターの動きやタイミングをよく考えて、丁寧に作成しようとしていました。 ディラックが歩いているときと立ち止まったときに使用するコスチュームの違いや、繰り返す回数なども、何通りか試してしっくりいくように調整していました。 わからないところを端的に質問できるようになってきました。', null, 'タイピング: 授業前に熱心にやっていました
盛り上がり: オープニングの動きが思い通りにできたようで、満足そうでした。'),
  ('9aa83d3c-42c0-5537-b4ec-203fe2a41191', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '作りたい素材があるようで（スプラトゥーンのようなイメージ）、熱心に表現方法を考えて何度も作りなおしていました。 コンテストに対する全体像を考える前に、自分で作ってみたいパーツがあるようなので、まずは本人の希望通りに作らせてから全体像を整えていく感じになりそうです。', null, '盛り上がり: どうしたら思い通りの表現ができるか、コスチュームやコードを一生懸命考えていました。授業終了直前にそれっぽい動きができたようで、ほっとしたように見せてくれました。'),
  ('677e24d6-e0f3-51b0-8ec1-58a448c8ecae', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-25', '17:30:00', null, '通常 / ゾンビを倒せを完成させよう', '前回に続いて、ゾンビを倒せを作っていきました。前回ビームのコードをゾンビに作ってしまったから、そこをややこしいことにならないようにゆったり進めました。ビームを作った時、流れではさいしょは1回きりのビームしか打てないようになっているので、そこでなんで1回しか打てないと疑問を持ってくれたのは良かったです。その解消として「端に触れたら止まる」ようにするコードを一緒に作っていきましたが、なぜそのようにするかは質問形式で作っていきましたが、かずま君は忘れやすいので次週ビームが何度も打てるようになった理由はもう1度確認が必要です。 いつもながら、意識があちこち行ってしまってなぜかコードや音が消えていることが多かったので、そこを少なくしてスムーズに進められるようにしたいです。 飴を食べた後に口の中を指でいじる癖があったので、「パソコンはみんなが使うものだから手を拭こうね」と注意したら、本人も悪いと思う自覚はあったので、良かったのですが、無意識でやっていることだと思うので、パソコンに触る前に注意しましょう', null, 'タイピング: タイピング中はアルファベット以外のところを触らないように
盛り上がり: 音にはこだわりを持って選んでいるな感じます'),
  ('855027de-b641-5e7a-95ac-87e642c08697', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-25', '17:30:00', null, '通常 / できれば親子大会の作品', 'レーンに流れる寿司をできるだけたくさんつかむゲームを作りました。若者が回転寿司屋で寿司を触る迷惑行為をしたというニュースを元ネタにしたそうです。四角形を組み合わせて寿司のコスチュームを描いたり、その寿司を次々と一定方向に流していったりとクオリティが高くて面白いゲームになりました。また、特定の場所を触ると警報音が鳴ってカオスな世界に変わるというまさきくんらしい要素も追加していました。最近は色々と作りこまれた良い作品ができることが多くなっていると思います。', null, '盛り上がり: 今日は早いうちから製作を始めていて集中していました。'),
  ('af0695f3-83e1-58dc-8419-7c2a1241bf1a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-25', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '今回はゲームではなくストーリーを見せる系でいきたいとのこと、テーマは「夢・保育士」だそうです。 承太郎君と一緒に素材を張り切って集めていました。保育士になる夢に、コロナ禍の生活での経験を入れていきたいとのことで、冒頭部分を作成していました。 画面の構成などは決まったようだったので、ストーリーの先を考えてくるよう伝えました。', '文字を順に出すだけで終わらないような工夫もあわせて考える', 'タイピング: いつも通りのスピードでした
盛り上がり: ストーリーを書き込んでいくことを楽しそうにやっていました。 イメージ自体はわいてきたようで、背景と登場人物を組み合わせるのを熱心にやっていました。'),
  ('59c3e545-17d9-5a0e-b40a-6de192a29a77', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-25', '16:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に、前年度のコンテストの優秀作の動画を見て、面白いアイデアを読み取ってもらいました。メダカやハチのゲームがお気に入りだった面白いと感じていました。そうちゃんは去年も釣りのゲームを作成したので、作る意欲はとても高かったです。選んだアイデアとしてバトル物が作りたいそうです。背景には見晴らしのいい芝生や山、途中で池の中で戦いたかったりしたいそうです。背景の絵として、そうちゃんの家の近くの公園の写真を撮って使いたいそうなので、写真を撮ってくるようにしました。敵の10体くらいも選んでいて、各敵ごとに相性のいい武器や鷹飼方ができたらいいねと共有しました。今回はゲームの大まかな流れを考えることができたので、次回からコードを作っていけたらいいと思います。', '各敵ごとの動き、背景の決定、コードづくり', 'タイピング: 以前やったところを復習していました
盛り上がり: みなみ野の公園生態を厚く話してくれました。'),
  ('20e0e639-4b08-54a7-9983-6d63a59cd06a', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-25', '17:30:00', null, '通常 / 親子大会', '主人公が弾丸をよける弾幕ゲームを作ることにしました。そこで【小技】弾幕東方シューティング風 02 基礎編 のコードを参考にすることを勧めたところ、それを見ながら自分なりにアレンジして作ることができました。回転させながらクローンを作り続けるというポイントを理解したようです。また、主人公の棒人間も追加しました。 最初は「カオスなゲームが一番面白い」とのことでとにかくたくさんの弾丸を発射してみたのですが、さすがに多すぎてよけきれないことが分かり量を調整していました。', null, 'タイピング: 楽しんで取り組んでいました
盛り上がり: 作っている作品をまさきくんと見せ合うなどして仲が良いです'),
  ('de448cb8-f0e5-553e-8b50-7b2e9677e636', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-25', '17:30:00', null, '通常 / コンテスト作品の構想、作成', '文字PV以外の作成意欲が少し下がっているのと、ゲーム部分は昨年かなり頑張って作ったので、あれ以上どうしたらよいのかわからなくなっている感があり、少し心配していました。今日は文字PV作成も一段落したとかで、しばらく考え込んでいましたが、以前に書き溜めていたストーリーがあるそうで、それを活用しようという気になったようでした。 これまでScratchの作品を閲覧しながら気に入った素材のサイトを自分で集めていたようで、今日はストーリーに合った背景や音楽などを収集して基本となる画面を作成していました。', null, 'タイピング: ゆきちゃんと一緒に楽しそうにやっています
盛り上がり: 素材を集めていくうちに作成意欲がわいてきたようで、授業終了時には「こんな感じで作っていきたい」と画面を見せてくれました。ストーリーを読ませる形の作品になりそうですが、承太郎君が一生懸命考えたお話とのことで、形にできるのが嬉しそうでした。
備考: 作品を作ろうという意識は上向いてきていますが、選抜大会の方はまだちょっとしり込みしている部分もあり…作品が仕上がってくると自信も戻ってくるかもしれないので、あまり強制せず、作成を楽しんでもらいながら様子を見て勧めていきたいところです。'),
  ('40ea75d3-ce4a-5c5c-9fed-20f70445aa4d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, null, '2023-05-25', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('65bb1827-c6e1-56ed-b0b2-3c5eee42a605', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', null, null, '通常 / 昨年の全国小中学生プログラミング大会の動画を視聴、構想を練る', '授業開始時は、コンテストに参加することを了承して動画視聴に入りましたが、見終わった後は、この大会はちょっと…という感じでした。他の大会もあるので、とりあえずオリジナル作品を作ってみないかと促してみましたが、昨年でやり切った感があったのか、今年は特にやりたいテーマが思いつかないとのこと、コンテストと資格試験のようなものだったらどちらに興味があるかと聞いたところ、資格試験と即答したので、ゆき先生に試験や教材の紹介をお願いしました。 最終的に、チエテラスの教材を熱心にやっていました。', null, '時間帯: その他
タイピング: よくできていました
盛り上がり: 資格試験という言葉にとても食いついてきて、チエテラスの教材も楽しそうに取り組んでいました。'),
  ('1c2db8bd-c2ca-5d3b-b915-1126a34a340a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '17:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に前年度の親子大会の優秀作の動画を見てもらい、面白うなアイデアを見て感じ取ってもらいました。テーマを決める際に、最初は作りたいものはないといっていたが、なかなか一人では外表れにくかったが、そこから先生に引き出してもらい考えていることがわかっていました。棒人間同士の戦いを作りたいそうです。今回は、まずは導入である棒人間のコスチュームパターンを作っていきました。数あるコスチュームを見てそれだけでストーリーが伝わってくる出来具合で、特に顔の表情が描くのが上手かったです。 背景の地球の溶け込み具合が気づきにくいくって、絵と得の組み合わせるのがとてもたけている思います。', null, null),
  ('1fb4cf42-2cb8-5d31-b47b-d6bde52a7e4d', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '16:30:00', null, '通常 / 教室の使い方を理解する、基本的なゲームを作ってみる', '前半の動画視聴は、興味を持って楽しそうに見ていました。 全体への説明が終わった後、ビギナーズ部門の説明をしたら「そっちをやりたい」とのこと、にじいろピンポンのPDF資料を見せながら作成しました。 作成しているところをそばで見ていてもらいたがる傾向が大きいながらも、説明書のどこを見てどこまでやればいいのか細かく指定すると、自分で文章を読んで真似して作成することはできました。 ボールがボタンスプライトの上をはずんで跳ね返った時は、とても興奮して喜んでいました。', null, 'タイピング: ココアタイピングに興味を示していました
盛り上がり: 作成自体にはとても興味を持って楽しそうに取り組んでいました。 自分で動かしたスプライトがボールを跳ね返すところでゲームを作成した実感が持てたのか、何度も試しては興奮して喜んでいました。'),
  ('151c061b-6185-50d4-976e-351147da84da', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '17:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に前年の親子大会の優秀作の動画を見てもらいました。面白いと感じるアイデアをみとってもらいました。テーマ基目に考えてもらうと、普段から遊んでいる功績を集めるクリックゲーをゴミ集めにアレンジしたいとすぐに思い浮かびました。実際に作り始めると、ごみ厚めに関する色合いや変数や使い道はそのゲームの幹のなるぶぶんは作りが速かったです。次回は、まずは簡素的にゲームを完成させ、それ以降の細部づくりに活かせていけたらいいと思います。', null, 'タイピング: 高速に終わらせていました。
盛り上がり: 背景選びや必要ヨウ素の考えの候補が速い'),
  ('5705f036-817a-5a18-a18c-326d999fd5e5', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-23', '16:30:00', null, '通常 / 全員コンテストに向けて準備開始 ◎作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しんで見ていました。 昨年の自分の作品もよく覚えていて、それなりの自負もありそうでした。 オリジナル作品のテーマ一覧を見て、少し難しめのものに挑戦したいと「SDGs」の中から選んでいました。当初はさらちゃん自身がよく意味のわからないテーマを選んで、何から手をつけていいか混乱していたので、自分でイメージがわくテーマにするように勧め、「飢餓」を選んでいました。 オープニングで飢餓について説明をし、飢餓をなくすためのゲームを挟んでエンディングにするという構成と、オープニングの説明用キャラクターを決め、説明文の作成に入ったところで終了しました。', null, '盛り上がり: さらちゃんなりに、昨年よりも上を目指したいという意欲はあるようで、面白いだけではなくまじめなテーマを選んで、説明文のために熱心に飢餓について調べていました。 見る人が少しでもわかりやすいように、説明をセリフではなく背景に直接書くようにするなど、工夫しようする姿勢も見られました。'),
  ('4a58ae56-6931-5df7-98d5-7198a7647c5f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '16:30:00', null, '通常 / コンテストに向けてアイデアを練ろう', '最初に親子大会の前回の動画を見てもらい、どのようなアイデアが自分の活かせるか考えてもらいました。ショウタ君的にはメダカのゲームが面白かったそうです。 なかなか、テーマ関連のものに興味を抱かなくて悩んでいたが、対戦系のものにテーマを決めて、ヒーローと魔王が闘う形に決めました。魔王の形が円形を組み合わせて、様々な形態を作っていたので、作り始めると構想は一気に広がっているように見えます。コスチュームごとの動きを次回考えていけたらいいと思います。', null, null),
  ('cd2fd1df-491f-59fd-869b-fc3679a1cf18', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-23', '16:30:00', null, '通常 / コンテストに向けてアイデアづくりをしよう', '最初に八王子の親子大会の前回の作品アーカイブを見て、使えそうなアイデアを考えました。まだ、経験が浅いので、ビギナー部門かオリジナル部門が作る方を選択するようにしましたが、動画を見て自由に作ってみたいことだったので、オリジナル部門の方で作り始めました。テーマに絞られずに作り始めたところ、ボールの上を飛び回るアスレチック系を作っていました。ボールから飛び移る際にジャンプの作り方がわからなくて詰まっていました。このゲームには自然落下のジャンプが必要と考えられるので、まずはジャンプの基礎をジャンプを見せて、原理を考えてもらいました。手早にやったので、あまり理解をできているかあやふやになったと思います。自然落下のジャンプを作るのはレベルが足らないので軌道修正をさせた方がいい。', null, '盛り上がり: コンテストの意欲は感じました。'),
  ('00370ba2-0a89-53d0-840b-788f6e497a7c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 追跡ゲームに使用するスキルの習得', 'こうしろうくんの誘いもあり、追跡ゲームに興味を示したので、席を横並びにして「一緒のゲームを作ってみよう」と声掛けをしたところ、大変乗り気になって、時間ギリギリまで「次のところもやる」と前向きに取り組んでいました。 座標についてはきちんと理解するところまでは至ったいませんが、アルファベットは良く読めていて本人もそれを自負しているようだったので、スプライトを手動で動かして、どの向きの動きのときに、どのアルファベットの数値が変わっているかを何度も見せたところ、xとyの使い分けの部分の作成はできました。 マイナスについては「知らない」とのことだったので、正解を作成してから動きの違いを確認させました。 スコアの変数の方が、イメージがわきやすいのか、理解が早かったです。', '追跡ゲームのレベルアップから', '時間帯: その他
タイピング: アルファベットはきちんと読めているので、キーの位置にさえ慣れればすぐに上達しそうです。
盛り上がり: こうしろうくんが一歩先のところを学習していたせいか、そちらを何度も見せてもらったり、こうしろうくんの説明を素直に聴いたりして、疲れたら二人分の飴を持ってきたりしながら楽しそうにやっていました。'),
  ('f8cb7bc1-f998-52e9-b2f5-e68d29692722', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画の視聴中、普段よりも感想を口にするなど積極的な反応が見られたので、作品の構想に入るところでゆうかちゃんと向い合わせ、講師を含めた3人でのおしゃべり形式にしてみました。普段のレッスンの細分化などでは、ゆうかちゃんが積極的に応答することもあり、黙りがちになってしまうのですが、今回は楽しそうにやりたいことをどんどん口にしてくれました。 マインクラフトのように、素材を集めて何かを作る形式にしたいとのことで、スプライトのドット絵にとても興味を示していました。iPadで描くことにもチャレンジしてみましたが、用意したいスプライトの数に到底追いつかなそうだったため、フリーのドット絵のサイトを教え、画像のダウンロードとアルスパークへのアップロードを習得させました。', '素材の準備をしつつ、全体的なイメージを少しずつ明確にしていきたいところです。', '時間帯: その他
タイピング: 少しずつ安定してきています
盛り上がり: まだイメージが曖昧な部分もありますが、自分で素材を用意してアイテム作成をする作品ができるかもしれない、ということがとても嬉しそうで、終始キラキラした感じでした。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
